INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027b57e3c98b0941765961', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有饮料送！以后来广州就认花园酒店', '["https://dimg04.c-ctrip.com/images/0233j12000f010s5vE4F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000f010zgm4FA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000f010ln4675A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-04', '花园双床房', '双床房', '家庭亲子', 55, 0, 10, 7, '["前台服务","交通便利性","公共设施"]'::jsonb, '前台服务', '交通便利性', '公共设施'),
('68027b57e3c98b0941765962', '房间很大，套房，睡得很舒服，酒店环境也很赞，两点不足，一就是1千多的房价迷你吧的饮料竟然全部收费。二就是入住时那个服务员竟然不知道我的价钱含早餐，然后询问了也答错了吃早餐的地方，新来的吗？要好好培训了。', '["https://dimg04.c-ctrip.com/images/0236712000e6adchd1B48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000e6ape0wE46D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000e6adqucA504_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000e6acsb80153_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000e6ahc482038_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000e6alhbhD4E7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000e6apqa70CBD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000e6adfacD59F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000e6al6pbB16B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-05-26', '花园大床房', '大床房', '家庭亲子', 101, 1, 44, 8, '["性价比","前台服务","整体满意度"]'::jsonb, '性价比', '前台服务', '整体满意度'),
('68027b57e3c98b0941765963', '环境优美，有个园林可以喂鱼，酒店有个博物馆，前台姐姐服务周到', '["https://dimg04.c-ctrip.com/images/0230o12000fmdr7osC013_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000fmdblc2C7EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-18', '花园大床房', '大床房', '家庭亲子', 30, 0, 4, 6, '["周边配套","前台服务"]'::jsonb, '周边配套', '前台服务', NULL),
('68027b57e3c98b0941765964', '来到酒店经理看到我们两大三小的组合，二话不说马上给换成了亲子套房，因为来的晚预订不到晚上自助餐位置了，经理又帮我们优先预约了第二轮自助餐，整个服务流程提现了专业以及关怀，非常满意的一次体验', '["https://dimg04.c-ctrip.com/images/0235p12000ejs51mj3693_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000ejs6oa42F5B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000ejs49903553_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000ejs8ro938BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-22', '花园双床房', '双床房', '家庭亲子', 94, 0, 4, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b57e3c98b0941765965', '花园酒店位置好，交通便利，酒店设施高端大气，服务热情周到，出行首选。', '["https://dimg04.c-ctrip.com/images/0232n12000fhjk3ncA909_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-10', '花园双床房', '双床房', '商务出差', 34, 0, 4, 6, '["交通便利性","整体满意度","公共设施"]'::jsonb, '交通便利性', '整体满意度', '公共设施'),
('68027b57e3c98b0941765966', '酒店干净卫生，住的很舒服，多住几晚体验感更好，生日酒店还送了一个小蛋糕，预定了一晚瀑布酒店，感觉一般般', '["https://dimg04.c-ctrip.com/images/0235a12000fh5nyyfE6A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000fh55t0g9328_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000fh535p8D93D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-09', '花园大床房', '大床房', '情侣出游', 51, 0, 4, 6, '["整体满意度","卫生状况","客房服务"]'::jsonb, '整体满意度', '卫生状况', '客房服务'),
('68027b57e3c98b0941765967', '感谢前台Gillian的服务，花园酒店的配套设施都很好，客房很宽敞，花园式的环境很漂亮，楼顶还有博物馆，虽小却也底蕴深厚', '["https://dimg04.c-ctrip.com/images/0234b12000ewlnwxg6B17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000ewlmb939063_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000ewlk9zjD027_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-26', '花园双床房', '双床房', '家庭亲子', 60, 0, 2, 8, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('68027b62e3c98b0941765968', '服务很好，酒店大堂大气，服务人员很热情', '["https://dimg04.c-ctrip.com/images/0230b12000g1kndec67A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 19, 0, 5, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027b62e3c98b0941765969', '环境是真的好，酒店大厅^-^气派 周边还有广州酒家 超级方便 地铁出来就是酒店 对于带娃的出行 节省不少时间了 太完美了??还贴心的送了小甜品', '["https://dimg04.c-ctrip.com/images/0236d12000fhoj4fv4ED1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000fhoj24r1292_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000fhojqth0589_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-10', '花园双床房', '双床房', '家庭亲子', 71, 0, 5, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027b62e3c98b094176596a', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，胜在洗澡水很冲洗的舒服，客服小李还亲自送来小甜品。出行地铁方便吃饭可选择余地比较多，就是周边那几家很红的餐厅都需要等位好久。', '["https://dimg04.c-ctrip.com/images/02302224x8z2z4ytt6503_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g224x8z303wfzF469_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q224x8z2yj3a76E66_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d224x8z2zap72D88B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z224x8z31aplv9284_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 102, 0, 12, 8, '["前台服务","退房/入住效率","交通便利性"]'::jsonb, '前台服务', '退房/入住效率', '交通便利性'),
('68027b62e3c98b094176596b', '床真舒适，美美的睡了一觉！30楼的旋转自助餐厅的食物太美味??瀑布花园太壮观了！', '["https://dimg04.c-ctrip.com/images/0236312000f90nsoy5FBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000f90pqupC156_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000f90lizoE984_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-25', '花园大床房', '大床房', '家庭亲子', 40, 0, 3, 6, '["餐饮设施","房间设施","整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度'),
('68027b62e3c98b094176596c', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '["https://dimg04.c-ctrip.com/images/0236c12000flnuonnCB2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000fln5rcq22FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000flnll3h961F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-17', '花园双床房', '双床房', '商务出差', 63, 0, 61, 0, '[]'::jsonb, NULL, NULL, NULL),
('68027b62e3c98b094176596d', '老牌五星，浓郁的老广州味，喜欢喜欢有年轻时候的回忆，服务特别好。真诚细致。特别感谢James。Man c.y', '["https://dimg04.c-ctrip.com/images/0232p12000fa965nh0786_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000fa95ujbE0CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000fa950wj913B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000fa970k3E6DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000fa96v1o6D29_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000fa93s5d8D95_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园大床房', '大床房', '朋友出游', 54, 0, 4, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027b62e3c98b094176596e', '酒店整体设施都比较完善，后花园很大，4楼还有个博物馆，是老品牌五星级酒店了，入住期间羊羊精品店Livia很热情，酒店的小羊超级可爱~', '["https://dimg04.c-ctrip.com/images/0236x12000epvv4698C02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000epvj5wl439B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-08', '花园大床房', '大床房', '商务出差', 66, 0, 4, 7, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68027b62e3c98b094176596f', 'echo小姐姐很棒 
卫生：很好
环境：优美
服务：态度好', '["https://dimg04.c-ctrip.com/images/0234d12000fi6hwa42562_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000fi6gjxu7BBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-11', '红棉大床套房', '套房', '商务出差', 29, 0, 23, 4, '["卫生状况","整体满意度","前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务'),
('68027b62e3c98b0941765970', '服务很好，环境舒适宜人，值得入住！', '["https://dimg04.c-ctrip.com/images/0231812000g0f456b6820_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000g0felxc6E41_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000g0f0uya1C6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '花园大床房', '大床房', '情侣出游', 17, 0, 2, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027b62e3c98b0941765971', '酒店虽老但服务还是很好，rose', '["https://dimg04.c-ctrip.com/images/0232f12000g1fusbi2E59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园大床房', '大床房', '朋友出游', 16, 0, 3, 4, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027b6de3c98b0941765972', '行政酒廊 Cathy 和 Echo 服务很好，希望行政酒廊食物种类可以更丰富。还有回访的小颖态度很赞。整体体验感很不错。', '["https://dimg04.c-ctrip.com/images/0236k12000fk0sqts0799_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235612000fk0omgeC335_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233c12000fk0t92v59D5_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-14', '花园大床房', '大床房', '家庭亲子', 60, 0, 3, 7, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b6de3c98b0941765973', '非常好的体验，老牌的星级酒店，服务态度很好，很多外国友人入住，位置不错！总体感觉很好，体验感很好！满意！', '["https://dimg04.c-ctrip.com/images/0236c12000f1lies8CB1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000f1led1vE69F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000f1lfxo292C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-08', '花园大床房', '大床房', '商务出差', 52, 0, 48, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027b6de3c98b0941765974', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，遇到的每一个服务生都很亲切，很有礼貌，4楼的博物馆记录了广州酒店的发展历程，值得一看', '["https://dimg04.c-ctrip.com/images/0235112000eexnpdrE6B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000eexdy0eCCEF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000eexdwl7FEDA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-10', '花园双床房', '双床房', '家庭亲子', 82, 0, 7, 8, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027b6de3c98b0941765975', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级酒店，服务一流，必须五星好评。', '["https://dimg04.c-ctrip.com/images/0232w12000evyma7p3A3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000evym581B6C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000evynw0z946D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-24', '花园双床房', '双床房', '家庭亲子', 55, 0, 4, 6, '["整体满意度","前台服务","性价比"]'::jsonb, '整体满意度', '前台服务', '性价比'),
('68027b6de3c98b0941765976', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，游泳池的服务，救生员都有三个，还有酒水部，迎宾，送水送毛巾，救生员小周热情服务，讲解，让客人游泳的很安心，餐饮服务都很好，特别行政酒廊30楼的金牌导游CARRIE，没在服务时间帮我女儿做了咖啡，端午节早餐人有点多，也只等了10分钟，吃完后还有经理来道歉，服务不周，很是感慨酒店服务人员的素质，
但我这里重点说一下前台服务，希望管理层能看到，前台是我这次住店体验不好的，工作人员没有认真看订单，先分配我去9楼房间，我的订单是18楼以上的，吃完饭一看不仅楼层低，还是尾房，后来交涉后给升级了，过程就不说了，其实最终还是住的升级房型，你一早给我不是不用这么麻烦，因为我也是你们金卡会员，在办理入住的时候看到柜台堆满了一支一支的康乃馨，是送给客人的，给我办理的工作人员没有任何触动，就在她手边。
大堂的迎宾小姐姐还会主动帮客人拍照，很美的酒店，希望前台能看到，不要给酒店拖后腿。', '["https://dimg04.c-ctrip.com/images/0233q12000ehd9s634411_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000ehdbnpq07B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000ehd8uj4D165_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-15', '花园双床房', '双床房', '家庭亲子', 425, 0, 26, 9, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('68027b6de3c98b0941765977', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好，在酒店吃了早餐和晚餐，菜式丰富，根本没办法一一品尝，非常满意，下次过来还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0200v12000ecnhcj491A5_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236q12000ecndo8v7249_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000ecmodmw7803_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000ecn0sciF7A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-06', '花园大床房', '大床房', '家庭亲子', 84, 0, 4, 8, '["整体满意度","餐饮设施","卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况'),
('68027b6de3c98b0941765978', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点，荔湾亭点心出品也是不错的！', '["https://dimg04.c-ctrip.com/images/0230312000ft5qzct8B64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000ft5pgz0B6DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000ft5db3lA7C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-09-28', '花园双床房', '双床房', '家庭亲子', 54, 0, 19, 7, '["整体满意度","周边配套","餐饮设施"]'::jsonb, '整体满意度', '周边配套', '餐饮设施'),
('68027b6de3c98b0941765979', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，很多老外，周边很多印度餐厅??', '["https://dimg04.c-ctrip.com/images/0235z12000f3q5d3w490C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000f3q0gksA33C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000f3q63f7228E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000f3py6ozCBD0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-13', '花园大床房', '大床房', '家庭亲子', 55, 0, 12, 5, '["性价比","交通便利性","周边配套"]'::jsonb, '性价比', '交通便利性', '周边配套'),
('68027b6de3c98b094176597a', '位置很好，出行方便，设施，卫生，前台服务也很不错。就是两点瑕疵：门童交接有空档，下大雨的天气，开车到了，也没人指引停车，接箱子；大堂引导员有点不在状态，不停私语，还望加强培训。', '["https://dimg04.c-ctrip.com/images/0230212000ec065utDC28_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000ec07sniF612_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000ec06f4u9A31_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-06-05', '花园大床房', '大床房', '情侣出游', 88, 0, 88, 8, '["交通便利性","前台服务","卫生状况"]'::jsonb, '交通便利性', '前台服务', '卫生状况'),
('68027b6de3c98b094176597b', '酒店环境很好，非常干净，服务好', '["https://dimg04.c-ctrip.com/images/0236j12000fzx7qu50D7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000fzx8q97F7EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 15, 0, 3, 4, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('68027b78e3c98b094176597c', '很有文化底蕴的酒店，博物馆超级棒', '["https://dimg04.c-ctrip.com/images/0236w12000fy62fnf40E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-03', '花园双床房', '双床房', '朋友出游', 16, 0, 2, 5, '["周边配套"]'::jsonb, '周边配套', NULL, NULL),
('68027b78e3c98b094176597d', '大堂气派！老牌酒店服务做得就是好，每天都有小惊喜，太贴心了！！自助早餐选择种类很多，必定有你喜欢??', '["https://dimg04.c-ctrip.com/images/0233a12000expvgr04BCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000expq3p464B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000expl8061A77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000expzr1eA69B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000exq6pze8950_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000expe2wr1961_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-29', '花园双床房', '双床房', '朋友出游', 50, 1, 9, 6, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b78e3c98b094176597e', '每次去广州都备注的一个酒店之一，环境不错，就是房间小一点，周围购物方便，去任何一个地方也很方便，最喜欢的就是酒店的花', '["https://dimg04.c-ctrip.com/images/0231712000fe6jhws5195_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000fe67pkmAA23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000fe69sfeA98E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000fe64twf7A01_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000fe62fel6C88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000fe6itpo2510_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000fe6fc7kFF65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000fe68gh277AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-04', '花园双床房', '双床房', '家庭亲子', 58, 0, 14, 5, '["周边配套","交通便利性","整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度'),
('68027b78e3c98b094176597f', '是什么好运让我在广州暴雨天气入住了花园酒店～
没有亲眼目睹花园酒店的瀑布后花园有点遗憾，
但其他都是很棒的体验～

所选的区域位置比较市中心，
无论去广州塔还是去沙面岛玩耍
居中的位置出行都比较方便。

大堂看着有点奢华，
一楼有瀑布餐厅以及下午茶??
定了两间双床和大床，
虽然是一样的价格，但大床房带浴缸
备好泡泡浴球可以带娃洗个泡泡浴??

早餐就是比较中规中矩的自助餐，
但点心这块很是吸引甜品爱好者～

下次来还是会住这里，希望可以天公作美～', '["https://dimg04.c-ctrip.com/images/0234112000dqrp8b3A0C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000dqs35ub817F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000dqrygc265ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000dqrm9ffD140_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000dqrv7zo8D09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000dqrtm9v3856_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000dqrrlmy5FD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000dqrvets4948_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000dqs07tl3A28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-21', '花园大床房', '大床房', '家庭亲子', 226, 0, 2, 8, '[]'::jsonb, NULL, NULL, NULL),
('68027b78e3c98b0941765980', '酒店位置出行方便 虽然是近40年前开业的第一批五星级酒店 但是并不觉得老旧 房间面积大分区合理 健身房设施齐备 后花园颇有岭南园林神韵值得一观 行政酒廊在顶层旋转餐厅 服务细致热情 唯一小缺憾是房间香氛有点类似于阿拉伯特点 略微不适应', '["https://dimg04.c-ctrip.com/images/0236t12000dz097al8949_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000dz06gndBBA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000dz06praC769_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000dz09bzt952F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000dz0chok2283_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000dz0arewE72C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-05-12', '红棉大床套房', '套房', '商务出差', 117, 0, 13, 9, '["交通便利性","公共设施","前台服务"]'::jsonb, '交通便利性', '公共设施', '前台服务'),
('68027b78e3c98b0941765981', '广州和南沙两家花园酒店都住了，自助晚餐都做得很一般，没啥好吃的，三文鱼质量也不行，这个房价实在性价比不高', '["https://dimg04.c-ctrip.com/images/0233912000f9r8nprDD39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000f9rbeufE2C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000f9r0v091B76_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 52, 0, 70, 7, '["性价比","餐饮设施"]'::jsonb, '性价比', '餐饮设施', NULL),
('68027b78e3c98b0941765982', '酒店环境非常棒，去各个景点都很方便，房间也干净，服务贴心，因为办理了续住，酒店还送了早餐，非常满意的一次体验', '["https://dimg04.c-ctrip.com/images/0234a12000euq7y18E6A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 54, 1, 16, 7, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况'),
('68027b78e3c98b0941765983', '很满意的一次住宿，环境好，早餐品种很丰富，一楼瀑布餐厅，三楼中餐厅，还有三十楼的行政酒廊，Carrie和Echo二位小姐姐很专业又很有礼貌，推荐，推荐', '["https://dimg04.c-ctrip.com/images/0233812000fm1dhv84875_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000fm1l9m63978_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000fm1n2p39706_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 75, 0, 1, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027b78e3c98b0941765984', '环境：优美 
服务：好????', '["https://dimg04.c-ctrip.com/images/0231u12000g1o6tn50BC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园大床房', '大床房', '商务出差', 15, 0, 18, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b78e3c98b0941765985', '房间很不错，服务也很到位。很有年代感的一家酒店，下次来还会光顾', '["https://dimg04.c-ctrip.com/images/0231512000faf0qm8BF9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000faemxpb50A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000faf0qe3E851_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 31, 0, 4, 5, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027b83e3c98b0941765986', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看到评论说因为酒店旧所以有霉味，到了房间之后发现完全是多虑了，房间一点味道也没有，地理位置也很棒，打车去各景点大概都在30元以内，出酒店门就是地铁，周边吃的也很多，很多热门的店周边都有分店。这次住的很满意。', '["https://dimg04.c-ctrip.com/images/0233m12000dxetxw3824B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000dxetq2t63C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-09', '花园大床房', '大床房', '家庭亲子', 142, 2, 11, 9, '["整体满意度","交通便利性","周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套'),
('68027b83e3c98b0941765987', '花园酒店位于城市市中心很方便，酒店的花园也很漂亮，服务也很好，大堂非常的华丽，?酒店大堂的花园大使小何服务很不错??', '["https://dimg04.c-ctrip.com/images/0231g12000jkt9idsDCE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000jkvevqu3D7B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-05', '花园大床房', '大床房', '独自旅行', 58, 0, 2, 7, '["交通便利性","前台服务"]'::jsonb, '交通便利性', '前台服务', NULL),
('68027b83e3c98b0941765988', '前台Zara和Viria的接待很热情，免费赠送了小朋友早餐。分别体验了一楼瀑布餐厅和30楼的旋转餐厅。', '["https://dimg04.c-ctrip.com/images/0237112000eyg3oyvD274_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-31', '红棉大床套房', '套房', '家庭亲子', 51, 0, 2, 7, '["前台服务","餐饮设施"]'::jsonb, '前台服务', '餐饮设施', NULL),
('68027b83e3c98b0941765989', '酒店环境好 很好看的酒店', '["https://dimg04.c-ctrip.com/images/0236812000h7w419cA60D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000h7w54971E27_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000h7w5xby4290_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-15', '花园大床房', '大床房', '朋友出游', 12, 0, 12, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027b83e3c98b094176598a', '淘金地铁站出来就是，但是门前交通不太方便，车进酒店要等很久。景观一般。设施是不错的，还有咖啡机，床比较大。', '["https://dimg04.c-ctrip.com/images/0232p12000f1iua68D2F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000f1j4a88ED4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000f1j2x9034BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000f1jixjm58A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-08-08', '花园大床房', '大床房', '商务出差', 53, 0, 33, 6, '["交通便利性","房间设施","景观/朝向"]'::jsonb, '交通便利性', '房间设施', '景观/朝向'),
('68027b83e3c98b094176598b', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位适中，值得再次入住', '["https://dimg04.c-ctrip.com/images/0234712000euodzsiDC77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000euoeeu1CAC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000euodu0k0685_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '红棉双床套房', '套房', '家庭亲子', 49, 0, 8, 6, '["前台服务","性价比","整体满意度"]'::jsonb, '前台服务', '性价比', '整体满意度'),
('68027b83e3c98b094176598c', '一路风雨来到广州，毕竟有悠久的历史，从城到人到酒店从美景到美食都丰富而厚重。
房间免费升级行政套房，17岁的少年免费加床，花园饭店真的有温暖到我，房间的细节让，辉煌的大堂，让多年来游历29国的我第一次感觉到宾至如归，结合国外很多博物馆的展品，终于明白了，他们当年为何那样推崇中国元素的装修。
床很舒服，布局合理，枕头可选择，香皂很香，拖鞋很软，自动窗帘方便又遮光，灯光很舒适，忘带房卡也不怕去，电梯口总有热情美丽的服务员。
地铁淘金站的旁边，地处越秀老城区，繁华方便，到各个景点都很方便，外国门童帮忙开门时，心中很骄傲，民族自豪感。
花园酒店让我的广州之行幸运，圆满，非常完美的入住体验，五星推荐！', '["https://dimg04.c-ctrip.com/images/0234r12000dw8f86oF987_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000dw8b2wp57B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000dw80ttu48CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-06', '花园大床房', '大床房', '家庭亲子', 299, 1, 2, 9, '["整体满意度","房间设施","交通便利性"]'::jsonb, '整体满意度', '房间设施', '交通便利性'),
('68027b83e3c98b094176598d', '花园酒店是老广心中机具代表性的酒店，从小就对酒店有着特殊的情感，今天终于有机会体验一次，房间做了升级，套房空间大，环境卫生可以，本次出行满意', '["https://dimg04.c-ctrip.com/images/0233a12000ehr67dgEACD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000ehr5tk4384C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000ehr62asB44C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000ehr6cmmF20E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000ehr69s836A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-16', '花园双床房', '双床房', '家庭亲子', 70, 0, 27, 6, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027b83e3c98b094176598e', '非常喜欢这家，每次来广州只选花园，服务和交通便利没话说，??', '["https://dimg04.c-ctrip.com/images/0236k12000fasuzin5F0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000fat7qt8C7EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-29', '花园大床房', '大床房', '家庭亲子', 30, 0, 17, 5, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027b83e3c98b094176598f', '位置:越秀区中心位置，近地铁，出行就餐方便。
惊喜:感谢前台艾薇儿，赠送了三份早餐，升级90平行政套房。风景绝佳，体验不俗。
氛围营造:文化气息浓郁的大堂，国风雅韵buff，春节还有室内庙会，年味浓郁。
服务:春节期间，实习生过多，有些跟不上，可以理解。
用餐:场地小，西餐偏多，喜欢粤式早茶的请飘过。
总体:老国产五星级，有自己的调性！', '["https://dimg04.c-ctrip.com/images/0235w12000i5avcz3470E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000i5ba4l67E26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000i5bw0hgFCB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000i5aqvur59D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-29', '花园双床房', '双床房', '商务出差', 169, 0, 5, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027b8fe3c98b0941765990', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，漂亮，卫生、服务好、出行方便。5??赞赞赞', '["https://dimg04.c-ctrip.com/images/0233z12000h9l85leD65B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000h9lcxopD6F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-18', '花园大床房', '大床房', '商务出差', 61, 0, 2, 7, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68027b8fe3c98b0941765991', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人员说只能现场支付。现场支付了20，最后结帐酒店又从押金中扣，两次投诉才拿回20元，整个过程匪夷所思，难道只有二次付款才能从押金里扣吗？！现场支付后工作人员不进行标注的吗？！区区20元，费的心力远不及此。更气的是住3天花将近5千，发票只开了1128元，莫名其妙的各种错！作为五星酒店的基本服务能力在哪里？！', '["https://dimg04.c-ctrip.com/images/0232a12000dwiyz6v6EF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-05-07', '花园双床房', '双床房', '朋友出游', 192, 2, 1, 9, '["前台服务","退房/入住效率","价格合理性"]'::jsonb, '前台服务', '退房/入住效率', '价格合理性'),
('68027b8fe3c98b0941765992', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动为客户提供超值的升级服务，从迎宾、接待、客房到环境和配套都名副其实，再次到广东还想入住花园酒店，感谢酒店管理者和服务人员的辛苦付出和优质服务，你们完全能代表中国五星级酒店品牌和形象！', '["https://dimg04.c-ctrip.com/images/0232q12000dwz2wpd7912_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231x12000dwz4561E5DA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231312000dwz3m5tD903_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-05-08', '花园双床房', '双床房', '商务出差', 131, 0, 2, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务')
 ON CONFLICT (_id) DO NOTHING;
